import ast
import os
import sys
from pathlib import Path

syntax_errors = []
quality_issues = {
    "unused_imports": [],
    "undefined_names": [],
    "todo_fixme": []
}

# Walk through all Python files
for root, dirs, files in os.walk("."):
    # Skip __pycache__ and .git
    dirs[:] = [d for d in dirs if d not in ["__pycache__", ".git", ".venv", "node_modules"]]

    for file in files:
        if not file.endswith(".py"):
            continue

        filepath = os.path.join(root, file)

        try:
            with open(filepath, "r") as f:
                content = f.read()

            # Check syntax
            ast.parse(content)

            # Check for TODO/FIXME comments
            for i, line in enumerate(content.split("\n"), 1):
                if "TODO" in line or "FIXME" in line:
                    quality_issues["todo_fixme"].append(f"{filepath}:{i}: {line.strip()}")

        except SyntaxError as e:
            syntax_errors.append(f"{filepath}:{e.lineno}: {e.msg}")
        except Exception as e:
            pass

# Print results
print("=" * 80)
print("SYNTAX ERRORS")
print("=" * 80)
if syntax_errors:
    for error in sorted(syntax_errors):
        print(f"❌ {error}")
else:
    print("✅ No syntax errors found")

print("\n" + "=" * 80)
print("TODO/FIXME COMMENTS")
print("=" * 80)
if quality_issues["todo_fixme"]:
    for issue in sorted(quality_issues["todo_fixme"])[:50]:
        print(f"⚠️  {issue}")
    if len(quality_issues["todo_fixme"]) > 50:
        print(f"\n... and {len(quality_issues['todo_fixme']) - 50} more TODO/FIXME comments")
else:
    print("✅ No TODO/FIXME comments found")
EOF
